if (!$input.item.binary?.data?.data) {
  throw new Error('No image binary from Drive download');
}
const base64 = $input.item.binary.data.data;
const mimeType = $input.item.binary.data.mimeType || 'image/jpeg';
const promptText = `You are processing an image for East Texas Krav Maga's media library. Return ONLY valid JSON, no preamble, no markdown.\n\n{\n  "description": "1-2 sentence factual description of what is in the image",\n  "tags": ["tag1","tag2","tag3"],\n  "content_use_cases": ["use case 1","use case 2"],\n  "asset_type": "Image",\n  "tone": "high-energy|calm-focus|community|instructional|real-world|confidence"\n}\n\nTag rules: assign 3-6 tags only from this list: training, demonstration, class, seminar, event, headshot, facility, equipment, group, individual, youth, adult, women, cbltac, social-ready, print-ready, web-ready, email-ready, testimonial-context, action-shot, portrait, environment, candid, posed, fight-back-etx, armed-citizen, youth-program, college-safety, private-lessons, open-enrollment, community-event, high-energy, calm-focus, community, instructional, real-world, confidence`;
const claudeBody = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{
    role: 'user',
    content: [
      { type: 'image', source: { type: 'base64', media_type: mimeType, data: base64 } },
      { type: 'text', text: promptText }
    ]
  }]
};
const originalFile = $('Drive — New File').item.json;
return {
  json: {
    originalFilename: originalFile.name || 'unknown',
    originalFileId: originalFile.id || '',
    claudeRequestBody: JSON.stringify(claudeBody)
  }
};

const claudeResponse = $input.item.json;
let content;
try {
  const body = typeof claudeResponse.body === 'string' ? JSON.parse(claudeResponse.body) : claudeResponse;
  content = body.content[0].text;
} catch (e) {
  content = (claudeResponse.content || [{}])[0]?.text || '{}';
}
let result;
try {
  result = JSON.parse(content);
} catch (e) {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
}
const prepData = $('Code — Prep').item.json;
const driveUrl = prepData.originalFileId ? `https://drive.google.com/file/d/${prepData.originalFileId}/view` : '';
return {
  json: {
    filename: prepData.originalFilename || 'unknown',
    description: result.description || '',
    tags: Array.isArray(result.tags) ? result.tags : [],
    content_use_cases: Array.isArray(result.content_use_cases) ? result.content_use_cases : [],
    asset_type: result.asset_type || 'Image',
    tone: result.tone || '',
    drive_url: driveUrl
  }
};
